// src/components/admin/AdminReviews.jsx
import React, { useEffect, useState } from "react";
import axios from "axios";

const API_BASE = process.env.REACT_APP_API_BASE || "http://localhost:8000";

export default function AdminReviews() {
  const [reviews, setReviews] = useState([]);
  const [stats, setStats] = useState(null);
  const [loading, setLoading] = useState(true);
  const [selectedReview, setSelectedReview] = useState(null);
  const [replyText, setReplyText] = useState("");
  const [submitting, setSubmitting] = useState(false);
  const [successMsg, setSuccessMsg] = useState("");

  useEffect(() => {
    fetchReviews();
    fetchStats();
  }, []);

  const fetchReviews = async () => {
    try {
      const response = await axios.get(`${API_BASE}/api/reviews/`);
      setReviews(response.data);
    } catch (err) {
      console.error("Error fetching reviews:", err);
    } finally {
      setLoading(false);
    }
  };

  const fetchStats = async () => {
    try {
      const response = await axios.get(`${API_BASE}/api/reviews/stats/`);
      setStats(response.data);
    } catch (err) {
      console.error("Error fetching stats:", err);
    }
  };

  const openReplyModal = (review) => {
    setSelectedReview(review);
    setReplyText(review.admin_reply || "");
    setSuccessMsg("");
  };

  const closeReplyModal = () => {
    setSelectedReview(null);
    setReplyText("");
    setSuccessMsg("");
  };

  const submitReply = async () => {
    if (!selectedReview) return;

    setSubmitting(true);
    try {
      await axios.patch(`${API_BASE}/api/reviews/${selectedReview.id}/`, {
        admin_reply: replyText,
      });
      setSuccessMsg("Reply submitted successfully!");
      fetchReviews();
      setTimeout(() => {
        closeReplyModal();
      }, 1500);
    } catch (err) {
      console.error("Error submitting reply:", err);
      setSuccessMsg("Failed to submit reply. Please try again.");
    } finally {
      setSubmitting(false);
    }
  };

  const formatDate = (dateString) => {
    if (!dateString) return "-";
    const date = new Date(dateString);
    return date.toLocaleDateString("en-IN", {
      year: "numeric",
      month: "short",
      day: "numeric",
    });
  };

  const renderStars = (rating) => {
    return "★".repeat(rating) + "☆".repeat(5 - rating);
  };

  return (
    <div style={{ display: "flex", minHeight: "100vh", background: "#181818", color: "#f1f1f1" }}>
      <style>{`
        :root{--bg-sidebar:#202020;--card:#2a2a2a;--accent:#c89d5c;--muted:#aaa}
        .sidebar-container{width:220px;min-height:100vh;background:var(--bg-sidebar);padding:20px;display:flex;flex-direction:column;position:fixed;top:0;left:0;height:100vh}
        .sidebar-title{color:var(--accent);font-size:20px;margin-bottom:24px;font-weight:600}
        .sidebar-nav{display:flex;flex-direction:column;flex:1}
        .sidebar-link{color:var(--muted);text-decoration:none;padding:10px 12px;border-radius:6px;margin-bottom:4px;transition:all 0.2s ease;display:block}
        .sidebar-link:hover{color:var(--accent);background:rgba(200,157,92,0.1)}
        .sidebar-link.active{color:var(--accent);background:rgba(200,157,92,0.15)}
        .sidebar-logout{margin-top:auto;padding-top:20px;border-top:1px solid #333}
        .main-content{flex:1;margin-left:220px;padding:28px;min-height:100vh}
        .page-title{color:var(--accent);font-size:28px;margin-bottom:20px}
        .stats-grid{display:grid;grid-template-columns:repeat(4,1fr);gap:18px;margin-bottom:24px}
        .stat-card{background:var(--card);padding:20px;border-radius:8px;text-align:center}
        .stat-card h4{color:var(--muted);margin-bottom:8px;font-size:14px}
        .stat-card p{font-size:28px;color:var(--accent);font-weight:700}
        .reviews-grid{display:grid;grid-template-columns:repeat(auto-fill,minmax(350px,1fr));gap:18px}
        .review-card{background:var(--card);padding:20px;border-radius:8px}
        .review-header{display:flex;justify-content:space-between;align-items:flex-start;margin-bottom:12px}
        .review-guest{color:var(--accent);font-weight:600;font-size:16px}
        .review-rating{color:#ffc107;font-size:18px}
        .review-meta{color:var(--muted);font-size:13px;margin-bottom:10px}
        .review-text{color:#ddd;line-height:1.5;margin-bottom:12px;padding:12px;background:rgba(0,0,0,0.2);border-radius:6px}
        .review-reply{background:rgba(200,157,92,0.1);padding:12px;border-radius:6px;margin-top:12px}
        .review-reply-label{color:var(--accent);font-size:13px;font-weight:600;margin-bottom:6px}
        .review-reply-text{color:#ddd;font-size:14px;line-height:1.5}
        .reply-btn{background:var(--accent);color:#111;border:none;padding:8px 16px;border-radius:6px;cursor:pointer;font-weight:600;margin-top:10px}
        .reply-btn:hover{opacity:0.9}
        .modal-overlay{position:fixed;inset:0;background:rgba(0,0,0,0.7);display:flex;align-items:center;justify-content:center;z-index:999}
        .modal-content{background:#2a2a2a;padding:24px;border-radius:12px;width:500px;max-width:90%}
        .modal-header{display:flex;justify-content:space-between;align-items:center;margin-bottom:16px}
        .modal-title{color:var(--accent);font-size:20px;margin:0}
        .modal-close{background:transparent;border:none;color:#fff;font-size:24px;cursor:pointer}
        .modal-textarea{width:100%;padding:12px;border-radius:8px;border:1px solid #444;background:#1e1e1e;color:#fff;min-height:120px;font-family:inherit;resize:vertical}
        .modal-actions{display:flex;gap:12px;justify-content:flex-end;margin-top:16px}
        .btn-cancel{background:#374151;color:#fff;border:none;padding:10px 20px;border-radius:6px;cursor:pointer}
        .btn-submit{background:var(--accent);color:#111;border:none;padding:10px 20px;border-radius:6px;cursor:pointer;font-weight:600}
        .empty-state{text-align:center;padding:60px;color:var(--muted)}
        @media(max-width:900px){.sidebar-container{display:none}.main-content{margin-left:0}.stats-grid{grid-template-columns:repeat(2,1fr)}}
      `}</style>

      <aside className="sidebar-container">
        <h2 className="sidebar-title">Admin</h2>
        <nav className="sidebar-nav">
          <a href="/admin" className="sidebar-link">Dashboard</a>
          <a href="/admin/reservations" className="sidebar-link">Reservations</a>
          <a href="/admin/rooms" className="sidebar-link">Rooms</a>
          <a href="/admin/customers" className="sidebar-link">Customers</a>
          <a href="/admin/calendar" className="sidebar-link">Calendar</a>
          <a href="/admin/guest-activity" className="sidebar-link">Guest Activity</a>
          <a href="/admin/staff" className="sidebar-link">Staff</a>
          <a href="/admin/gallery" className="sidebar-link">Gallery</a>
          <a href="/admin/reviews" className="sidebar-link active">Reviews</a>
        </nav>
        <div className="sidebar-logout">
          <a href="/login" className="sidebar-link">Logout</a>
        </div>
      </aside>

      <main className="main-content">
        <h1 className="page-title">Guest Reviews</h1>

        {/* Stats Cards */}
        {stats && (
          <div className="stats-grid">
            <div className="stat-card">
              <h4>Total Reviews</h4>
              <p>{stats.total_reviews}</p>
            </div>
            <div className="stat-card">
              <h4>Average Rating</h4>
              <p>{stats.average_rating} ★</p>
            </div>
            <div className="stat-card">
              <h4>5-Star Reviews</h4>
              <p>{stats.rating_distribution?.[5] || 0}</p>
            </div>
            <div className="stat-card">
              <h4>4-Star Reviews</h4>
              <p>{stats.rating_distribution?.[4] || 0}</p>
            </div>
          </div>
        )}

        {/* Reviews List */}
        {loading ? (
          <div className="empty-state">Loading reviews...</div>
        ) : reviews.length === 0 ? (
          <div className="empty-state">
            <p>No reviews yet. Reviews will appear here after guests submit them.</p>
          </div>
        ) : (
          <div className="reviews-grid">
            {reviews.map((review) => (
              <div key={review.id} className="review-card">
                <div className="review-header">
                  <div>
                    <div className="review-guest">{review.guest_name}</div>
                    <div className="review-meta">
                      {review.room_type} • {formatDate(review.check_out)}
                    </div>
                  </div>
                  <div className="review-rating">{renderStars(review.rating)}</div>
                </div>

                <div className="review-text">{review.review_text}</div>

                <div className="review-meta">
                  Reviewed on {formatDate(review.created_at)}
                </div>

                {review.admin_reply ? (
                  <div className="review-reply">
                    <div className="review-reply-label">Admin Reply:</div>
                    <div className="review-reply-text">{review.admin_reply}</div>
                  </div>
                ) : (
                  <button
                    onClick={() => openReplyModal(review)}
                    className="reply-btn"
                  >
                    Reply to Review
                  </button>
                )}
              </div>
            ))}
          </div>
        )}
      </main>

      {/* Reply Modal */}
      {selectedReview && (
        <div className="modal-overlay">
          <div className="modal-content">
            <div className="modal-header">
              <h2 className="modal-title">Reply to Review</h2>
              <button onClick={closeReplyModal} className="modal-close">×</button>
            </div>

            <div style={{ marginBottom: 16 }}>
              <div style={{ color: "#c89d5c", fontWeight: 600, marginBottom: 8 }}>
                Guest: {selectedReview.guest_name}
              </div>
              <div style={{ color: "#ffc107", marginBottom: 8 }}>
                Rating: {renderStars(selectedReview.rating)}
              </div>
              <div style={{ color: "#aaa", fontSize: 14 }}>
                "{selectedReview.review_text}"
              </div>
            </div>

            {successMsg ? (
              <div style={{ 
                color: successMsg.includes("success") ? "#9ef59e" : "#ff7676",
                textAlign: "center",
                padding: 20 
              }}>
                {successMsg}
              </div>
            ) : (
              <>
                <textarea
                  className="modal-textarea"
                  value={replyText}
                  onChange={(e) => setReplyText(e.target.value)}
                  placeholder="Write your reply to this review..."
                />
                <div className="modal-actions">
                  <button onClick={closeReplyModal} className="btn-cancel">
                    Cancel
                  </button>
                  <button 
                    onClick={submitReply} 
                    className="btn-submit"
                    disabled={submitting || !replyText.trim()}
                  >
                    {submitting ? "Sending..." : "Send Reply"}
                  </button>
                </div>
              </>
            )}
          </div>
        </div>
      )}
    </div>
  );
}
